// get all data in form and return object
function getFormData(form) {
    var elements = document.getElementById(form).elements; // all form elements
    var fields = Object.keys(elements).map(function (k) {
        if (elements[k].name !== undefined) {
            return elements[k].name;
        }
    }).filter(function (item, pos, self) {
        return self.indexOf(item) == pos && item;
    });
    var data = {};
    fields.forEach(function (k) {
        data[k] = elements[k].value;
        if (elements[k].type === "checkbox") {
            data[k] = elements[k].checked;
        }
    });
    console.log(data);
    return data;
}

jQuery('img[src$=".svg"]').each(function() {
    var $img = jQuery(this);
    var imgID = $img.attr('id');
    var imgClass = $img.attr('class');
    var imgURL = $img.attr('src');
    var data_id = $img.attr('data-id');
    var data_parent = $img.attr('data-parent');

    jQuery.get(imgURL, function(data) {
        // Get the SVG tag, ignore the rest
        var $svg = jQuery(data).find('svg');

        // Add replaced image's ID to the new SVG
        if (typeof imgID !== 'undefined') {
            $svg = $svg.attr('id', imgID);
        }
        // Add replaced image's classes to the new SVG
        if (typeof imgClass !== 'undefined') {
            $svg = $svg.attr('class', imgClass + ' replaced-svg');
        }

        if (typeof data_id !== 'undefined') {
            $svg = $svg.attr('data-id', data_id);
        }

        if (typeof data_parent !== 'undefined') {
            $svg = $svg.attr('data-parent', data_parent);
        }

        // Remove any invalid XML tags as per http://validator.w3.org
        $svg = $svg.removeAttr('xmlns:a');

        // Replace image with new SVG
        $img.replaceWith($svg);

    }, 'xml');

});

