function audioPlay(){


    var audioPlayer = document.querySelector('.green-audio-player');
    var playPause = audioPlayer.querySelector('#playPause');
    var playpauseBtn = audioPlayer.querySelector('.play-pause-btn');
    var loading = audioPlayer.querySelector('.loading');
    var progress = audioPlayer.querySelector('.progress');
    var sliders = audioPlayer.querySelectorAll('.slider');
    var volumeBtn = audioPlayer.querySelector('.volume-btn');
    var volumeControls = audioPlayer.querySelector('.volume-controls');
    var volumeProgress = volumeControls.querySelector('.slider .progress');
    var player = audioPlayer.querySelector('audio');
    var currentTime = audioPlayer.querySelector('.current-time');
    var totalTime = audioPlayer.querySelector('.total-time');
    var speaker = audioPlayer.querySelector('#speaker');

    var draggableClasses = ['pin'];
    var currentlyDragged = null;

    window.addEventListener('mousedown', function (event) {

        if (!isDraggable(event.target)) return false;

        currentlyDragged = event.target;
        var handleMethod = currentlyDragged.dataset.method;

        this.addEventListener('mousemove', window[handleMethod], false);

        window.addEventListener('mouseup', function () {
            currentlyDragged = false;
            window.removeEventListener('mousemove', window[handleMethod], false);
        }, false);
    });

    playpauseBtn.addEventListener('click', togglePlay);
    player.addEventListener('timeupdate', updateProgress);
    player.addEventListener('volumechange', updateVolume);
    player.addEventListener('loadedmetadata', function () {
        totalTime.textContent = formatTime(player.duration);
    });
    player.addEventListener('canplay', makePlay);
    player.addEventListener('ended', function () {
        playPause.attributes.d.value = "M18 12L0 24V0";
        player.currentTime = 0;
    });

    volumeBtn.addEventListener('click', function () {
        volumeBtn.classList.toggle('open');
        volumeControls.classList.toggle('hidden');
    });

    window.addEventListener('resize', directionAware);

    sliders.forEach(function (slider) {
        var pin = slider.querySelector('.pin');
        slider.addEventListener('click', window[pin.dataset.method]);
    });

    directionAware();

    function isDraggable(el) {
        var canDrag = false;
        var classes = Array.from(el.classList);
        draggableClasses.forEach(function (draggable) {
            if (classes.indexOf(draggable) !== -1) canDrag = true;
        });
        return canDrag;
    }

    function inRange(event) {
        var rangeBox = getRangeBox(event);
        var rect = rangeBox.getBoundingClientRect();
        var direction = rangeBox.dataset.direction;
        if (direction == 'horizontal') {
            var min = rangeBox.offsetLeft;
            var max = min + rangeBox.offsetWidth;
            if (event.clientX < min || event.clientX > max) return false;
        } else {
            var min = rect.top;
            var max = min + rangeBox.offsetHeight;
            if (event.clientY < min || event.clientY > max) return false;
        }
        return true;
    }

    function updateProgress() {
        var current = player.currentTime;
        var percent = current / player.duration * 100;
        progress.style.width = percent + '%';

        currentTime.textContent = formatTime(current);
    }

    function updateVolume() {
        volumeProgress.style.height = player.volume * 100 + '%';
        if (player.volume >= 0.5) {
            speaker.attributes.d.value = 'M14.667 0v2.747c3.853 1.146 6.666 4.72 6.666 8.946 0 4.227-2.813 7.787-6.666 8.934v2.76C20 22.173 24 17.4 24 11.693 24 5.987 20 1.213 14.667 0zM18 11.693c0-2.36-1.333-4.386-3.333-5.373v10.707c2-.947 3.333-2.987 3.333-5.334zm-18-4v8h5.333L12 22.36V1.027L5.333 7.693H0z';
        } else if (player.volume < 0.5 && player.volume > 0.05) {
            speaker.attributes.d.value = 'M0 7.667v8h5.333L12 22.333V1L5.333 7.667M17.333 11.373C17.333 9.013 16 6.987 14 6v10.707c2-.947 3.333-2.987 3.333-5.334z';
        } else if (player.volume <= 0.05) {
            speaker.attributes.d.value = 'M0 7.667v8h5.333L12 22.333V1L5.333 7.667';
        }
    }

    function getRangeBox(event) {
        var rangeBox = event.target;
        var el = currentlyDragged;
        if (event.type == 'click' && isDraggable(event.target)) {
            rangeBox = event.target.parentElement.parentElement;
        }
        if (event.type == 'mousemove') {
            rangeBox = el.parentElement.parentElement;
        }
        return rangeBox;
    }

    function getCoefficient(event) {
        var slider = getRangeBox(event);
        var rect = slider.getBoundingClientRect();
        var K = 0;
        if (slider.dataset.direction == 'horizontal') {

            var offsetX = event.clientX - slider.offsetLeft;
            var width = slider.clientWidth;
            K = offsetX / width;
        } else if (slider.dataset.direction == 'vertical') {

            var height = slider.clientHeight;
            var offsetY = event.clientY - rect.top;
            K = 1 - offsetY / height;
        }
        return K;
    }

    function rewind(event) {
        if (inRange(event)) {
            player.currentTime = player.duration * getCoefficient(event);
        }
    }

    function changeVolume(event) {
        if (inRange(event)) {
            player.volume = getCoefficient(event);
        }
    }

    function formatTime(time) {
        var min = Math.floor(time / 60);
        var sec = Math.floor(time % 60);
        return min + ':' + (sec < 10 ? '0' + sec : sec);
    }

    function togglePlay() {
        if (player.paused) {
            playPause.attributes.d.value = "M0 0h6v24H0zM12 0h6v24h-6z";
            player.play();
        } else {
            playPause.attributes.d.value = "M18 12L0 24V0";
            player.pause();
        }
    }

    function makePlay() {
        playpauseBtn.style.display = 'block';
        loading.style.display = 'none';
    }

    function directionAware() {
        if (window.innerHeight < 250) {
            volumeControls.style.bottom = '-54px';
            volumeControls.style.left = '54px';
        } else if (audioPlayer.offsetTop < 154) {
            volumeControls.style.bottom = '-164px';
            volumeControls.style.left = '-3px';
        } else {
            volumeControls.style.bottom = '52px';
            volumeControls.style.left = '-3px';
        }
    }
}

$(document).ready(function () {

    if( document.querySelector(".green-audio-player") != null ){

        audioPlay();

    }

    AOS.init();

    $('video').mediaelementplayer({

	   pluginPath: 'https://cdnjs.com/libraries/mediaelement/',
	   shimScriptAccess: 'always'
     });


    objectFitImages();

    $('.ios-parallax').iosParallax();
    /* Create an alert to show if the browser is IE or not */
    if (detectIE() == false || detectIE >= 12){

    }else{

        $(":input").each(function(){
            var input = $(this).attr('data-placeholder');
            $(this).val(input);
        });
    }

    $(":checkbox").labelauty();
    $(".form-radio").labelauty();

    $('.jarallax').jarallax({
        speed: 0.2
    });

    const selectfirst = document.querySelectorAll('.awesome-sel');

    if (selectfirst == null) {

    } else {

        [...selectfirst].forEach(cselect => {
            console.dir(cselect);

            var id = cselect.id;

            new SlimSelect({
                select: '#'+ $.trim(id)
            });


        });


    }
    var wow = new WOW({
        boxClass: 'wow', // animated element css class (default is wow)
        animateClass: 'animated', // animation css class (default is animated)
        offset: 50, // distance to the element when triggering the animation (default is 0)
        mobile: true, // trigger animations on mobile devices (default is true)
        live: true, // act on asynchronously loaded content (default is true)
        callback: function (box) {
            // the callback is fired every time an animation is started
            // the argument that is passed in is the DOM node being animated
        },
        scrollContainer: "window" // optional scroll container selector, otherwise use window
    });
    wow.init();


    //$('.swipebox-video').modalVideo();
    $('.venobox').venobox();

    $(document).on('click', '.over-trigger', function (e) {

        e.preventDefault();
        $(this).toggleClass('active');
        $('.set-overlay').toggleClass('open');

    });

    $(".rslides").responsiveSlides();
    $('.Uni').flexslider({
        selector: '.slides > li',
        animation: 'fade',
        direction: 'vertical',
        controlsContainer: $(".custom-controls-container"),
        customDirectionNav: $(".custom-navigation a"),
        start: function(slider) {

            window.setTimeout(function(){

                $('.slider-content').addClass('activate');
                $('.slider-content').addClass('fadeInUp');

            }, 500);



        },
        before: function(slider) {
            var current, first, next, prev;
            $('.slider-content').removeClass('activate');
            $('.slider-content').removeClass('fadeInUp');
            console.log("fired");
        },
        after: function(slider) {
            var current, slide;
            window.setTimeout(function(){

                $('.slider-content').addClass('activate fadeInUp');

            }, 500);
        },
        end: function(slider) {
            var first;

            $('.slider-content').removeClass('activate fadeInUp');
        }
    });


    var glide = new Glide('.glide', {
        type: 'carousel',
        perView: 4,
        focusAt: 'center',
        breakpoints: {
            800: {
                perView: 2
            },
            480: {
                perView: 1
            }
        }
    });

    // glide.mount();



    $('#cascade-blocks').cascadingDivs();

    $('a[href*="#"]:not([href="#"])').click(function() {

        if (location.pathname.replace(/^\//, '') == this.pathname.replace(/^\//, '') && location.hostname == this.hostname) {
            var target = $(this.hash);
            target = target.length ? target : $('[name=' + this.hash.slice(1) + ']');
            if (target.length) {
                $('html, body').animate({
                    scrollTop: (target.offset().top - 54)
                }, 1500, "easeInOutExpo");
                return false;
            }
        }
    });

    var animation_elements = $('.Bob-loop');

    $('.svg-replace').each(function () {
        var $img = $(this);
        var imgID = $img.attr('id');
        var imgClass = $img.attr('class');
        var imgURL = $img.attr('src');

        $.get(imgURL, function (data) {
            // Get the SVG tag, ignore the rest
            var $svg = $(data).find('svg');

            // Add replaced image's ID to the new SVG
            if (typeof imgID !== 'undefined') {
                $svg = $svg.attr('id', imgID);
            }
            // Add replaced image's classes to the new SVG
            if (typeof imgClass !== 'undefined') {
                $svg = $svg.attr('class', imgClass + ' replaced-svg');
            }

            // Remove any invalid XML tags as per http://validator.w3.org
            $svg = $svg.removeAttr('xmlns:a');

            // Replace image with new SVG
            $img.replaceWith($svg);

        }, 'xml');

    });

    var loopName = "carousel";

    $('.slide-fade').textSlider({

        timeout: 5500,
        slideTime: 1000,
        loop: 1

    });

    var $btns = $('.filter-btn').click(function () {
        var parent = $(this).attr("data-parent-filter");
        if (this.id == 'all') {
            $('#' + parent + '  .filter-b ').not(".f-menu").animate({
                opacity: 0
            }, 800, function () {
                // Animation complete.
                $(this).hide();
            });
            $('#' + parent + '  .filter-b ').not(".f-menu").animate({
                opacity: 1
            }, 500, function () {
                // Animation complete.
                $(this).fadeIn();
            });
        } else {
            var $el = $('.' + this.id).animate({
                opacity: 0
            }, 500, function () {
                // Animation complete.
                $(this).hide();
            });
            $('#' + parent + ' .filter-b ').not($el).not(".f-menu").animate({
                opacity: 0
            }, 500, function () {
                // Animation complete.
                $(this).hide();
            });
            $('.' + this.id).animate({
                opacity: 1
            }, 500, function () {
                // Animation complete.
                $(this).fadeIn();
            });
            $('#' + parent + ' .f-menu ').fadeIn();
        }
        $btns.removeClass('current');
        $(this).addClass('current');
    })

    $('#pager-6').paginate({

        // how many items per page
        perPage: 6,

        // scroll to top of the container if an user clicks on a pagination link
        auto: true,

        // which elements to target
        scope: 'div .filter-b',

        // where the pagination will be displayed
        paginatePosition: ['bottom'],

        // custom html tags for the pagination
        containerTag: 'nav',
        paginationTag: 'ul',
        itemTag: 'li',
        linkTag: 'a',

        // use hash locations
        useHashLocation: true,

        // triggered when a pagination link is clicked
        onPageClick: function () {}

    });

    //$('.select').niceSelect();


    $(window).scroll(function() {
        if ($(this).scrollTop() > 250){
            $('.sticky-nav-top').addClass("sticky-part");
        }
        else{
            $('.sticky-nav-top').removeClass("sticky-part");
        }
    });


    getSlidersOnePage();


});


function getSlidersOnePage(){

    var sliders = [];



    var elementExists = document.querySelector('[data-slider]');

    if(elementExists == null){

    }else{


        $('[data-slider]').each(function(){

            var type  = $(this).attr("data-slider-type");
            var items = $(this).attr("data-slider-items");
            var value = $(this).attr("data-slider-value");
            var autoplay = $(this).attr("data-slider-autoplay");
            var id = $(this).attr("id");

            var slide = {
                type :type,
                name :value,
                autoplay : autoplay,
                items :items,
            };
            sliders.push(slide);

            if(type == "tiny-slider"){

                var slider = tns({
                    container: "." + value,
                    items: items,
                    slideBy: 'page',
                    autoplay: autoplay
                });


            }else if(type == "pogo-slider"){

                $('.' + value).pogoSlider({
                    autoplay: true,
                    autoplayTimeout: 5000,
                    displayProgess: true,
                    generateNav:false,
                    responsive: true
                }).data('plugin_pogoSlider');

            }

        });

    }
}

