$(document).ready(function() {

    if ($('#back-to-top').length) {
        var scrollTrigger = 100, // px
            backToTop = function () {
                var scrollTop = $(window).scrollTop();
                if (scrollTop > scrollTrigger) {
                    $('#back-to-top').addClass('show');
                } else {
                    $('#back-to-top').removeClass('show');
                }
            };
        backToTop();
        $(window).on('scroll', function () {
            backToTop();
        });
        $('#back-to-top').on('click', function (e) {
            e.preventDefault();
            $('html,body').animate({
                scrollTop: 0
            }, 700);
        });
    }

    var there = document.querySelector('.nav-collapse');

    if(there == null || there == undefined){}else{

    var nav = responsiveNav(".nav-collapse", { // Selector
        animate: true, // Boolean: Use CSS3 transitions, true or false
        transition: 284, // Integer: Speed of the transition, in milliseconds
        label: "Menu", // String: Label for the navigation toggle
        insert: "before", // String: Insert the toggle before or after the navigation
        customToggle: "#hamburger-1", // Selector: Specify the ID of a custom toggle
        closeOnNavClick: false, // Boolean: Close the navigation when one of the links are clicked
        openPos: "relative", // String: Position of the opened nav, relative or static
        navClass: "nav-collapse", // String: Default CSS class. If changed, you need to edit the CSS too!
        navActiveClass: "js-nav-active", // String: Class that is added to  element when nav is active
        jsClass: "js", // String: 'JS enabled' class which is added to  element
        init: function(){}, // Function: Init callback
        open: function(){}, // Function: Open callback
        close: function(){} // Function: Close callback
    });

    }
    // you
    // process the form
    $('form.normal-form').submit(function(event) {
        event.preventDefault();


        // get the form data
        // there are many ways to get this data using jQuery (you can use the class or id also)
        if ($(this).parsley().isValid()) {

            var formID = $(this).attr('id');
            var formData = getFormData(formID);
            var url = $(this).attr("action");

            // process the form
            $.ajax({
                type: 'POST', // define the type of HTTP verb we want to use (POST for our form)
                url: url, // the url where we want to POST
                data: formData, // our data object
                dataType: 'json', // what type of data do we expect back from the server
                encode: true
            })
                .done(function(data) {


                if(data == "sent"){
                    swal(
                        'Good job!',
                        formData._confirmation,
                        'success'
                    );

                }else{

                    swal(
                        'Good job!',
                        data,
                        'success'
                    );
                }

                // here we will handle errors and validation messages
            });

            // stop the form from submitting the normal way and refreshing the page

        }

    });


});

