$(document).ready(function () {

    $(".datetime-pick").flatpickr({enableTime: true});
    $(".date-pick").flatpickr({enableTime: false});

    $(".menu-ham").click(function () {
        $(".site-overlay").fadeToggle(200);
    });

    $('.overlay').on('click', function () {
        $(".site-overlay").fadeToggle(200);
    });

    $('.top-menu li a').on('click', function () {
        $(".site-overlay").fadeToggle(200);
    });

    $('#nav-icon1,#nav-icon2,#nav-icon3,#nav-icon4').click(function(){
        $(this).toggleClass('open');
    });

    const soundr = document.querySelector('.background-music');


    if (soundr == null) {


    }else{

        var patht =  '/img/';

        var mp3 = $(".background-music").attr('data-sound');
        var sound = new Howl({
            src: [patht + mp3 + '.ogg', patht + mp3 + '.mp3', patht + mp3 + '.wav'],
            autoplay: true,
            loop: true,
            volume: 0.5,
            onend: function() {
                console.log('Finished!');
            }
        });

        console.log(patht + mp3 + '.mp3');



    }

    $("document").on('click','.stop-playing',function(){

        sound.pause();

    });

    $("document").on('click','.start-playing',function(){

        sound.play();

    });


    $(document).on('click', ".menu-less-tab", function () {

        var target = $(this).attr("data-target");
        var location = $(this).attr("data-left");

        var spli = target.split("-");
        if (spli[0] == "block" || spli[0] == "section") {

            var hash = "#";

        } else {

            var hash = ".";
        }

        if( $(hash + target).hasClass('menu-less-show')){

            $(hash + target).removeClass('menu-less-show');
            $(hash + target).css( {'left':'-500px !important;'});
            $('.menu-less-tab').removeClass('active');

        }else{

            $(hash + target).addClass('menu-less-show');
            $(hash + target).css( {"left" : location +'px !important;'});
            $('.menu-less-tab').addClass('active');

        }

    });
});

$(document).ready(function(){

    $(document).on('click',".chatbox-open",function(){
        $(".chatbox-popup, .chatbox-close").fadeIn()
    });

    $(document).on('click',".chatbox-close",function(){
        $(".chatbox-popup, .chatbox-close").fadeOut();
    });

    $(document).on('click',".chatbox-close",function(){
        $(".chatbox-popup, .chatbox-close").fadeOut();
    });

    $(document).on('click',".chatbox-maximize",function(){
        $(".chatbox-popup, .chatbox-open, .chatbox-close").fadeOut();
        $(".chatbox-panel").fadeIn();
        $(".chatbox-panel").css({ display: "flex" });
    });

    $(document).on('click',".chatbox-minimize",function(){
        $(".chatbox-panel").fadeOut();
        $(".chatbox-popup, .chatbox-open, .chatbox-close").fadeIn();
    });

    $(document).on('click',".chatbox-panel-close",function(){
        $(".chatbox-panel").fadeOut();
        $(".chatbox-open").fadeIn();
    });
});

